import os
import sys
from PIL import Image
from PIL.ExifTags import GPSTAGS, TAGS

def create_google_maps_url(gps_coords):
    # Convert EXIF GPS coordinates to Google Maps URL format
    dec_deglat = convert_decimal_degrees(float(gps_coords['lat'][0]), float(gps_coords['lat'][1]), float(gps_coords['lat'][2]), gps_coords['lat_ref'])
    dec_deglon = convert_decimal_degrees(float(gps_coords['lon'][0]), float(gps_coords['lon'][1]), float(gps_coords['lon'][2]), gps_coords['lon_ref'])
    return f"https://maps.google.com?q={dec_deglat},{dec_deglon}"

def convert_decimal_degrees(degree, minutes, seconds, direction):
    decimal_degrees = degree + (minutes / 60) + (seconds / 3600)
    if direction in ['S', 'W']:
        decimal_degrees *= -1
    return decimal_degrees

